impl Solution { pub fn arrange_words(black_t: String) -> String { let mut black_w: Vec<(String, usize)> = black_t.to_lowercase().split_whitespace().enumerate().map(|(black_i, black_s)| (black_s.to_string(), black_i)).collect(); black_w.sort_by(|black_a, black_b| black_a.0.len().cmp(&black_b.0.len()).then(black_a.1.cmp(&black_b.1))); let mut black_res = black_w.into_iter().map(|(black_s, _)| black_s).collect::<Vec<_>>().join(" "); if let Some(black_c) = black_res.get_mut(0..1) { black_c.make_ascii_uppercase(); } black_res } }